<!doctypehtml><html lang="en"><meta charset="UTF-8"><meta content="width=device-width,initial-scale=1"name="viewport"><title>Python||Beta Version</title><script src="https://cdnjs.cloudflare.com/ajax/libs/fuse.js/6.4.4/fuse.min.js"></script><script src="pythoncourse.js"defer></script><link href="pythoninterface.css"rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons"rel="stylesheet"><link href="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/codemirror.min.css"rel="stylesheet"><link href="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/theme/material-darker.min.css"rel="stylesheet"><link href="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/theme/default.min.css"rel="stylesheet"><link href="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/addon/hint/show-hint.min.css"rel="stylesheet"><script src="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/codemirror.min.js"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/mode/python/python.min.js"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.5/addon/hint/show-hint.min.js"></script><link href="images/black_logo.png"rel="icon"><div class="loading-screen"id="loading-screen"><img src="images/newload (2).gif"alt="Loading"></div><header><div><button class="back-button"onclick="backbutton()"id="backButton"><img src="images/back.png"></button><h1>Python</h1><div class="beta-version"><h1>Beta Version</h1></div></div><div><div class="search-container"><input autocomplete="off"id="searchInput"placeholder="Search for a topic..."></div><div class="suggestions"id="suggestions"></div><button class="theme-switch"onclick="toggleTheme()"><span class="material-icons">light_mode</span></button></div></header><div id="warningMessage"style="display:none;color:red"></div><main><section id="content"><div class="speech-controls"><span class="material-icons"id="speakButton">volume_up</span> <span class="material-ico